import GeneralArticles from '../components/GeneralArticles'
import TechnicalArticles from '../components/TechnicalArticles'
import Projects from '../components/Projects'
import Artworks from '../components/Artworks'
import Simulations from '../components/Simulations'
import Animations from '../components/Animations'

const Index = () => {
  return (
    <>
      <style>{styles}</style>
        <div className="page-wrapper">  
        <div className='introduction'>
          <Title/>
        </div>
        <div>
          <Row components={[ <TechnicalArticles/>, <GeneralArticles/>]}/>
          <Row components={[<Projects/>, <Artworks/>]}/>
          <Row components={[<Simulations/>, <Animations/>]}/>
        </div>
        <AboutMe/>
      </div>
    </>
  );
};

const Row = ({components}) => (
  <>
  <div style={{ display:'flex', flexDirection:'row', justifyContent:'space-between' }}>
    <div style={{ width:'50%' }}>
      {components[0]}
    </div>
    <div style={{ width:'50%' }}>
      {components[1]}
    </div>
  </div>
  </>
)

const AboutMe = () => (
  <div>About me</div>
)

const Title = () => (
  <div>
    <h1 className='title'>Wenuwake</h1>
    <div className='sub-title'>
      Portfolio website of Jithin KS
    </div>
  </div>
)

const styles = `
    .page-wrapper {
        width:80vw;
        margin:auto;
        font-family:Roboto;
    }
    .title {
      display: inline-block;
      margin:0;
    }
    .sub-title {
      display: inline-block;
      margin-left: 0.5rem;
    }
`;

export default Index;
